import React, { useState, useEffect, useRef } from 'react';
import api from './api';

export default function DicomViewer({ reportId, findings }) {
  const [imgUrl, setImgUrl] = useState(null);
  const [metadata, setMetadata] = useState(null);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(true);
  const [zoom, setZoom] = useState(1);
  const [brightness, setBrightness] = useState(100);
  const [contrast, setContrast] = useState(100);
  const [invert, setInvert] = useState(false);
  const imgRef = useRef();

  useEffect(() => {
    loadDicom();
    return () => { if (imgUrl) URL.revokeObjectURL(imgUrl); };
  }, [reportId]);

  const loadDicom = async () => {
    setLoading(true); setError('');
    try {
      const [imgRes, metaRes] = await Promise.all([
        api.get(`/dicom/view/${reportId}`, { responseType: 'blob' }),
        api.get(`/dicom/metadata/${reportId}`)
      ]);
      const url = URL.createObjectURL(imgRes.data);
      setImgUrl(url);
      setMetadata(metaRes.data.metadata);
    } catch (e) {
      setError(e.response?.data?.error || 'Failed to load DICOM');
    }
    setLoading(false);
  };

  const resetView = () => { setZoom(1); setBrightness(100); setContrast(100); setInvert(false); };

  if (loading) return (
    <div className="card text-center py-10">
      <div className="animate-spin h-10 w-10 border-4 border-blue-500 border-t-transparent rounded-full mx-auto mb-3"/>
      <p className="text-gray-500">Loading DICOM viewer...</p>
    </div>
  );

  if (error) return (
    <div className="card text-center py-10">
      <div className="text-4xl mb-2">⚠️</div>
      <p className="text-red-600">{error}</p>
      <p className="text-sm text-gray-400 mt-2">Make sure the file is a valid DICOM image</p>
    </div>
  );

  return (
    <div className="space-y-4">
      <div className="grid md:grid-cols-3 gap-4">
        {/* Controls */}
        <div className="card space-y-4">
          <h3 className="font-bold text-lg">🎛️ Controls</h3>

          <div>
            <label className="text-sm font-medium flex justify-between">
              <span>Zoom</span><span>{Math.round(zoom*100)}%</span>
            </label>
            <input type="range" min="0.5" max="3" step="0.1" value={zoom}
              onChange={e=>setZoom(parseFloat(e.target.value))} className="w-full"/>
          </div>

          <div>
            <label className="text-sm font-medium flex justify-between">
              <span>Brightness</span><span>{brightness}%</span>
            </label>
            <input type="range" min="20" max="300" value={brightness}
              onChange={e=>setBrightness(parseInt(e.target.value))} className="w-full"/>
          </div>

          <div>
            <label className="text-sm font-medium flex justify-between">
              <span>Contrast</span><span>{contrast}%</span>
            </label>
            <input type="range" min="20" max="300" value={contrast}
              onChange={e=>setContrast(parseInt(e.target.value))} className="w-full"/>
          </div>

          <label className="flex items-center gap-2 text-sm cursor-pointer">
            <input type="checkbox" checked={invert} onChange={e=>setInvert(e.target.checked)}
              className="rounded"/>
            Invert Colors
          </label>

          <button onClick={resetView} className="btn-gray w-full text-sm">Reset View</button>

          {/* Metadata */}
          {metadata && (
            <div className="border-t pt-3 space-y-1">
              <h4 className="font-semibold text-sm mb-2">📋 DICOM Info</h4>
              {Object.entries(metadata).filter(([k])=>k!=='findings').map(([k,v])=>(
                <div key={k} className="flex justify-between text-xs">
                  <span className="text-gray-500">{k}</span>
                  <span className="font-medium text-right max-w-[60%] truncate">{v}</span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Image viewer */}
        <div className="md:col-span-2 card p-2">
          <div className="bg-black rounded-lg overflow-hidden flex items-center justify-center"
               style={{ minHeight: '400px' }}>
            {imgUrl && (
              <img ref={imgRef} src={imgUrl} alt="DICOM"
                style={{
                  transform: `scale(${zoom})`,
                  filter: `brightness(${brightness}%) contrast(${contrast}%) ${invert?'invert(1)':''}`,
                  transition: 'transform 0.2s, filter 0.2s',
                  maxWidth: '100%', maxHeight: '500px',
                  objectFit: 'contain'
                }}/>
            )}
          </div>
        </div>
      </div>

      {/* Findings */}
      {findings && (
        <div className="card border-l-4 border-blue-500">
          <h3 className="font-bold mb-1">📝 Pathologist Findings</h3>
          <p className="text-gray-700">{findings}</p>
        </div>
      )}
    </div>
  );
}
